document.addEventListener('DOMContentLoaded',function(){var dropdown=document.querySelector('.hc-blog-search-filter--field select[name="category"]');var contentContainer=document.querySelector('.hc-blog-index--content');var fetchUrl;var selectedValue;if(dropdown&&contentContainer){dropdown.onchange=function(){selectedValue=this.value;if(selectedValue){contentContainer.style.opacity='0.5';if(selectedValue==0){fetchUrl=roketto_pillar.blog_url}else{fetchUrl=roketto_pillar.home_url+roketto_pillar.category_base+selectedValue}
fetch(fetchUrl).then(response=>response.text()).then(htmlString=>{var parser=new DOMParser();var doc=parser.parseFromString(htmlString,'text/html');var newContent=doc.querySelector('.hc-blog-index--content');if(newContent){contentContainer.innerHTML=newContent.innerHTML}else{console.error('Target selector not found in fetched page.')}
contentContainer.style.opacity='1'}).catch(error=>{console.error('Error fetching category:',error);contentContainer.style.opacity='1'})}}}})